body.script:
    (async function() {
        const contentDiv = document.getElementById('content');

        try {
            // Determine which site this is from the URL
            const siteUrl = window.location.origin;
            const pathParts = window.location.pathname.split('/');
            const siteDomain = pathParts[2] || window.location.hostname;

            // Map your domains to site IDs
            const siteMap = {
                'zeitgeist.de': 'zeitgeist',
                'nordlicht.de': 'nordlicht',
                'landleben.geizfoto.de': 'landleben',
                // Add all your sites here!
            };

            const siteId = siteMap[siteDomain] || 'unknown';

            if (siteId === 'unknown') {
                throw new Error('Site nicht erkannt: ' + siteDomain);
            }

            const GIST_ID = '42ea11087f40fdba423f8eb0f575ac96';
            const GIST_OWNER = 'Hamzamain-spec';
            const sitemapUrl = `https://gist.githubusercontent.com/${GIST_OWNER}/${GIST_ID}/raw/sitemap_${siteId}.xml`;

            const response = await fetch(sitemapUrl);

            if (!response.ok) {
                throw new Error('Sitemap nicht gefunden');
            }

            const sitemapXml = await response.text();

            // Display as XML
            contentDiv.innerHTML = '';
            const pre = document.createElement('pre');
            pre.style.textAlign = 'left';
            pre.style.background = '#f5f5f5';
            pre.style.padding = '20px';
            pre.style.overflow = 'auto';
            pre.style.borderRadius = '8px';
            pre.textContent = sitemapXml;
            contentDiv.appendChild(pre);

        } catch (e) {
            contentDiv.innerHTML = `

❌ Fehler



${e.message}

Mögliche Ursachen:


Noch keine Sitemap generiert

GitHub Token fehlt

Keine Artikel vorhanden


→ Zum Admin-Bereich

            `;
        }
    })();
